mapper.select:
SELECT TSL.ID, TSL.EXAMINE_MONTH, TSL.START_DATE, TSL.END_DATE, NVL(SD.DEPT_NAME,' ') DEPT_NAME, DECODE(TSL.FLAG, '0', '审核', '1', '撤销', '') FLAG, TSL.CREATE_TIME, dbms_lob.substr(TSL.ERR_MSG) ERR_MSG FROM T_PRD_SALARY_LOG TSL LEFT JOIN SYS_DEPT SD ON TSL.DEPT_ID = SD.ID
AND TSL.START_DATE = #{startDate,jdbcType=TIMESTAMP}
AND TSL.END_DATE = #{endDate,jdbcType=TIMESTAMP}
AND TSL.DEPT_ID = #{deptId, jdbcType=BIGINT}
AND TSL.DEPT_ID IS NULL

